#include <iostream>
#include <string>
#include <sstream>
#include <vector>

void run_test_case(const std::string& input, const std::string& expected_output) {
    std::stringstream ss_input(input);
    std::stringstream ss_output;

    // Redirect std::cin and std::cout
    std::streambuf* old_cin = std::cin.rdbuf();
    std::streambuf* old_cout = std::cout.rdbuf();
    std::cin.rdbuf(ss_input.rdbuf());
    std::cout.rdbuf(ss_output.rdbuf());

    main(); // Call the user's main function

    // Restore std::cin and std::cout
    std::cin.rdbuf(old_cin);
    std::cout.rdbuf(old_cout);

    std::string actual_output = ss_output.str();
    if (actual_output == expected_output) {
        std::cout << "Test passed for input: \"" << input << "\"" << std::endl;
    } else {
        std::cout << "Test failed for input: \"" << input << "\"" << std::endl;
        std::cout << "  Expected: \"" << expected_output << "\"" << std::endl;
        std::cout << "  Actual:   \"" << actual_output << "\"" << std::endl;
    }
}

int main() {
    std::vector<std::pair<std::string, std::string>> test_cases = {
        { "A", "Enter a character: A is an uppercase vowel.\n" },
        { "E", "Enter a character: E is an uppercase vowel.\n" },
        { "I", "Enter a character: I is an uppercase vowel.\n" },
        { "O", "Enter a character: O is an uppercase vowel.\n" },
        { "U", "Enter a character: U is an uppercase vowel.\n" },
        { "B", "Enter a character: B is not an uppercase vowel.\n" },
        { "a", "Enter a character: a is not an uppercase vowel.\n" },
        { "Z", "Enter a character: Z is not an uppercase vowel.\n" },
        { "5", "Enter a character: 5 is not an uppercase vowel.\n" },
        { "@", "Enter a character: @ is not an uppercase vowel.\n" }
    };

    for (const auto& tc : test_cases) {
        run_test_case(tc.first, tc.second);
    }

    return 0;
}
